generated_oml:
// Acting Component - PLC controlling the robot
instance SINUMERIKPLCActuator : DTDFVocab:ActingComponent [
    base:desc "Programmable Logic Controller (Siemens SINUMERIK 840D) that executes robot drive commands and interfaces with the industrial network."
]

// Sensing Components - joint telemetry sensors
instance JointAngleSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor measuring joint angles of the MABI MAX 100 robot."
    DTDFVocab:producedData RobotTelemetryTransmission
]

instance EncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Encoder capturing joint encoder counts for the MABI MAX 100 robot."
    DTDFVocab:producedData RobotTelemetryTransmission
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor measuring motor currents of the MABI MAX 100 robot."
    DTDFVocab:producedData RobotTelemetryTransmission
]

// Data Transmitted via MQTT
instance RobotTelemetryTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom JointAngleSensor,EncoderSensor,MotorCurrentSensor
]

// Aggregated Telemetry Data
instance RobotTelemetryData : DTDFVocab:Data [
    base:desc "Aggregated telemetry of joint angles, encoder counts, and motor currents from the MABI MAX 100 robot."
    DTDFVocab:inputTo MQTTEnabler
    DTDFVocab:fromData RobotTelemetryTransmission
]

// Enablers
instance MathWorksMATLABSimulinkEnabler : DTDFVocab:Enabler [
    base:desc "MathWorks MATLAB/Simulink used for developing physics‑based plant models and generating code for real‑time execution."
]

instance AssetAdministrationShellEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell (ISA95 compliant) providing a digital asset representation of the robot."
]

instance MQTTEnabler : DTDFVocab:Enabler [
    base:desc "MQTT protocol used for streaming telemetry from the robot to the digital twin."
    DTDFVocab:enables FrictionEstimationService
]

instance OPCUAEnabler : DTDFVocab:Enabler [
    base:desc "OPC‑UA used as an alternative interface for legacy systems."
]

instance GrafanaHMIDashboardEnabler : DTDFVocab:Enabler [
    base:desc "Grafana employed for HMI dashboards consuming twin state data."
]

instance NodeREDHMIDashboardEnabler : DTDFVocab:Enabler [
    base:desc "Node-RED used for constructing operator dashboards and visualizations."
]

// Model
instance SimulinkFrictionModel : DTDFVocab:Model [
    base:desc "Physics‑based model of robot joint dynamics and friction forces implemented in MATLAB/Simulink."
    DTDFVocab:inputTo MathWorksMATLABSimulinkEnabler
]

// Service
instance FrictionEstimationService : DTDFVocab:Service [
    base:desc "Continuous, multi‑physics aware identification of joint friction for each axis, enabling real‑time refinement of motion models."
    DTDFVocab:provides FrictionMetricInsight,ControlAdjustmentAction
]

// Insight
instance FrictionMetricInsight : DTDFVocab:Insight [
    base:desc "Displays joint friction metrics on the real‑time dashboard."
]

// Action
instance ControlAdjustmentAction : DTDFVocab:Action [
    base:desc "Pushes corrective control instructions back to the SINUMERIK 840D PLC."
    DTDFVocab:IsAutomatic true
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "Based on the MBSE approach outlined in Document 1, the Digital Twin system orchestrates its components using a layered architecture defined through Specification and Description languages such as SysML for high‑level functional and logical views and architecture description languages (e.g., ACME, AADL, MontiArc) for component‑connector modeling. The framework supports a multi‑level abstraction pipeline—requirements, functional architecture, logical architecture, and product/technical layers—allowing interoperability between heterogeneous modeling notations. Component behavior is expressed via state machines in SysML v1.7 or MontiArc Automaton, and executed or simulated with tools such as MathWorks Simulink or general‑purpose code (C++/Java). Resource allocation and coordination between subsystems are managed by integrating the models into a simulation engine (e.g., Simulink) that resolves data exchanges, propagates state changes, and enforces consistency across the twin. The overall coordination follows established MBSE methodologies such as RFLP, OOSEM, SPES, and SMArDT, which prescribe structured workflows for requirement traceability, function decomposition, logical design, and physics‑based execution, thereby ensuring a synchronized, verifiable digital representation of the physical product."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The system adopts standard modelling and interoperability frameworks: architectural models are expressed in SysML; the digital twin follows the Asset Administration Shell (AAS) specification for digital asset representation; integration interfaces comply with industry‑standard protocols to support data exchange within Industry 4.0 ecosystems."
]
